// ── REAL ESTATE (150+) ──
export const RE_FLASHCARDS: Flashcard[] = [
  // FUNDAMENTALS (30)
  { q: "What is NOI?", a: "Net Operating Income = Revenue - Operating Expenses (excludes debt service, CapEx, taxes). Core real estate cash flow metric.", category: "Fundamentals" },
  { q: "What is a cap rate?", a: "NOI / Property Value. Measures yield on a property. Lower cap rate = higher price relative to income.", category: "Fundamentals" },
  { q: "Cap rate and value relationship?", a: "Inversely related. Cap rates rise → values fall. Value = NOI / Cap Rate.", category: "Fundamentals" },
  { q: "What is a going-in vs exit cap rate?", a: "Going-in: cap rate at acquisition. Exit: assumed cap rate at sale. Exit is usually higher (property older/riskier).", category: "Fundamentals" },
  { q: "What drives cap rates?", a: "Interest rates, risk perception, supply/demand, property quality, location, lease profile, growth expectations.", category: "Fundamentals" },
  { q: "What is occupancy rate?", a: "% of rentable space that is leased. Higher = more stable income. Vacancy = 1 - occupancy.", category: "Fundamentals" },
  { q: "What is effective gross income?", a: "Potential gross income - vacancy loss + other income. Revenue actually expected to be collected.", category: "Fundamentals" },
  { q: "What is a triple-net (NNN) lease?", a: "Tenant pays rent plus taxes, insurance, and maintenance. Landlord has minimal operating risk.", category: "Fundamentals" },
  { q: "What is a gross lease?", a: "Landlord pays operating expenses. Tenant pays flat rent. More risk to landlord.", category: "Fundamentals" },
  { q: "What is tenant improvement (TI)?", a: "Landlord-funded buildout of tenant space. Higher TI = lower effective rent. Important in lease economics.", category: "Fundamentals" },
  { q: "What is lease-up risk?", a: "Risk of not filling vacant space. New developments and value-add projects face this risk.", category: "Fundamentals" },
  { q: "What are the main property types?", a: "Multifamily, office, retail, industrial, hospitality, self-storage, data centers, life science, senior living.", category: "Fundamentals" },
  { q: "What is absorption?", a: "Net change in occupied space over a period. Positive = more space occupied. Key demand indicator.", category: "Fundamentals" },
  { q: "What is a WALT?", a: "Weighted Average Lease Term. Longer WALT = more income certainty. Important for valuation stability.", category: "Fundamentals" },
  { q: "What is replacement cost?", a: "Cost to build an equivalent property today. Provides a floor for existing property values.", category: "Fundamentals" },
  // MODELING & RETURNS (30)
  { q: "What is a pro forma?", a: "Projected financials for a real estate investment: revenue, expenses, NOI, debt service, returns, exit.", category: "Modeling" },
  { q: "What is cash-on-cash return?", a: "Annual pre-tax cash flow / total cash invested. Simple yield metric, ignores appreciation.", category: "Modeling" },
  { q: "What is IRR in real estate?", a: "Annualized return accounting for timing of all cash flows: acquisition, operations, capital events, sale.", category: "Modeling" },
  { q: "What is an equity multiple?", a: "Total distributions / total equity invested. 2.0x = doubled your money.", category: "Modeling" },
  { q: "What is LTV?", a: "Loan-to-Value = Loan / Property Value. Measures leverage. Higher LTV = more leverage/risk.", category: "Modeling" },
  { q: "What is DSCR?", a: "Debt Service Coverage Ratio = NOI / Debt Service. Measures ability to cover payments. Lenders want >1.2x.", category: "Modeling" },
  { q: "What is a waterfall structure?", a: "Distributes cash flows in tiers: preferred return to LPs → GP catch-up → profit split (e.g., 80/20).", category: "Modeling" },
  { q: "What is a preferred return?", a: "Minimum return LPs receive before GP earns promote. Typically 8%.", category: "Modeling" },
  { q: "What is a promote?", a: "GP's share of profits above the preferred return. Similar to carried interest in PE.", category: "Modeling" },
  { q: "What is a lookback provision?", a: "Ensures LPs receive their preferred return over the entire hold period, not just annually.", category: "Modeling" },
  { q: "How do you project rent growth?", a: "Market rent trends, lease escalations (fixed or CPI-linked), mark-to-market on lease expiry.", category: "Modeling" },
  { q: "What is CapEx reserve?", a: "Annual budget for capital improvements (roof, HVAC, lobby). Reduces cash available for distribution.", category: "Modeling" },
  { q: "What is an amortizing vs interest-only loan?", a: "Amortizing: pay principal + interest. IO: pay only interest for a period. IO = higher cash flow, lower equity build.", category: "Modeling" },
  { q: "How do you calculate unlevered yield?", a: "NOI / total cost (acquisition + closing + CapEx). Return before financing.", category: "Modeling" },
  { q: "What is a yield-on-cost?", a: "Stabilized NOI / total development cost. Key metric for development feasibility.", category: "Modeling" },
  // STRATEGY & REITS (25)
  { q: "Core vs Value-Add vs Opportunistic?", a: "Core: stabilized, 6-8% return. Value-Add: improvement potential, 12-18%. Opportunistic: development/distressed, 18%+.", category: "Strategy" },
  { q: "What is value-add real estate?", a: "Properties needing improvement (renovation, re-leasing, management) to increase NOI and value.", category: "Strategy" },
  { q: "What is ground-up development?", a: "Building from scratch. Highest risk (entitlement, construction, lease-up) but potentially highest returns.", category: "Strategy" },
  { q: "What is a 1031 exchange?", a: "Tax-deferred exchange: sell one property, buy another of equal/greater value. Defers capital gains.", category: "Strategy" },
  { q: "What is FFO?", a: "Funds From Operations = NI + D&A - gains on sales. Standard REIT earnings metric.", category: "REITs" },
  { q: "What is AFFO?", a: "Adjusted FFO = FFO - maintenance CapEx - straight-line rent adjustments. Better cash flow proxy.", category: "REITs" },
  { q: "Why is FFO used instead of NI for REITs?", a: "Real estate depreciation overstates expense. Properties often appreciate. FFO removes this distortion.", category: "REITs" },
  { q: "What is NAV for a REIT?", a: "Net Asset Value: value of properties (NOI/cap rate) minus debt plus other assets. Compare to stock price.", category: "REITs" },
  { q: "Premium vs discount to NAV?", a: "Premium: stock > NAV (market values growth/management). Discount: stock < NAV (market skeptical).", category: "REITs" },
  { q: "What is a REIT?", a: "Real Estate Investment Trust. Must distribute 90%+ of taxable income. Provides liquidity and diversification.", category: "REITs" },
  { q: "What is same-store NOI growth?", a: "NOI growth from properties owned in both periods. Strips out acquisition effects. Shows organic performance.", category: "REITs" },
  // DEBT & MARKET (20)
  { q: "What types of RE debt exist?", a: "Senior mortgage, mezzanine, CMBS, construction loans, bridge loans, preferred equity. Different risk/return/priority.", category: "Debt" },
  { q: "What is CMBS?", a: "Commercial Mortgage-Backed Securities. Pooled commercial mortgages sold as bonds. Provides market-rate financing.", category: "Debt" },
  { q: "What is mezzanine debt in RE?", a: "Subordinate to senior mortgage. Higher rate, fills gap between senior debt and equity. Secured by ownership interest.", category: "Debt" },
  { q: "What is a bridge loan?", a: "Short-term financing for transitional properties. Higher rate, typically 1-3 years. Used during value-add period.", category: "Debt" },
  { q: "What is a rate lock?", a: "Agreement fixing the interest rate before closing. Protects against rate increases during due diligence.", category: "Debt" },
  { q: "How do rising rates affect real estate?", a: "Cap rates expand (values fall), financing becomes expensive, transaction volume drops, but rents may offset in inflation.", category: "Debt" },
  { q: "What is a recourse vs non-recourse loan?", a: "Recourse: lender can pursue borrower's other assets. Non-recourse: limited to the property. Most CMBS is non-recourse.", category: "Debt" },
  { q: "What is a debt yield?", a: "NOI / Loan Amount. Lender-focused metric — what return does the property produce on the loan regardless of rates.", category: "Debt" },
  // BEHAVIORAL (15)
  { q: "Why real estate?", a: "Tangible assets, inflation protection, income generation, leverage, intersection of finance and operations.", category: "Behavioral" },
  { q: "What property type interests you most?", a: "Pick one. Know supply/demand dynamics, cap rate trends, key players, recent transactions.", category: "Behavioral" },
  { q: "Tell me about a deal you've analyzed.", a: "Property type, location, strategy, return profile, key risks. Show analytical depth.", category: "Behavioral" },
  { q: "What market are you bullish/bearish on?", a: "Pick a specific city or property type. Support with data on supply, demand, demographics, employment.", category: "Behavioral" },
  { q: "How would you evaluate a property?", a: "Location, physical condition, tenant quality, lease terms, NOI stability, comps, basis vs replacement cost.", category: "Behavioral" },
  { q: "Tell me about yourself.", a: "Interest in real assets → analytical skills → relevant experience → why RE combines finance with tangible outcomes.", category: "Behavioral" },
];

// ── VENTURE CAPITAL (150+) ──
export const VC_FLASHCARDS: Flashcard[] = [
  // FUNDAMENTALS (25)
  { q: "What is venture capital?", a: "Investing in early-stage, high-growth companies for equity. High failure rate offset by outsized returns on winners.", category: "Fundamentals" },
  { q: "What is the power law in VC?", a: "Most returns come from a tiny number of investments. One company may return the entire fund.", category: "Fundamentals" },
  { q: "Seed vs Series A vs Series B?", a: "Seed: idea/early product, $1-5M. A: product-market fit, $5-25M. B: scaling, $20-100M+. Each has different risk/return.", category: "Fundamentals" },
  { q: "What is a cap table?", a: "Capitalization table showing ownership %, share classes, option pools, and dilution from each round.", category: "Fundamentals" },
  { q: "What is an option pool?", a: "Shares reserved for employee equity compensation. Usually 10-20% of fully diluted shares. Created/expanded at funding rounds.", category: "Fundamentals" },
  { q: "What is dilution?", a: "Reduction in ownership % when new shares are issued. Each funding round dilutes existing shareholders.", category: "Fundamentals" },
  { q: "What is a down round?", a: "Funding at a lower valuation than the previous round. Triggers anti-dilution provisions. Signals distress.", category: "Fundamentals" },
  { q: "What is product-market fit?", a: "When a product satisfies strong market demand. Signs: organic growth, high retention, word-of-mouth.", category: "Fundamentals" },
  { q: "What makes a great VC investment?", a: "Massive market, exceptional founders, PMF, strong unit economics, defensibility, reasonable valuation.", category: "Fundamentals" },
  { q: "How do VCs make money?", a: "Management fees (2% of committed capital) + carried interest (20% of profits above hurdle). Carry is the real upside.", category: "Fundamentals" },
  { q: "What is a VC fund lifecycle?", a: "Typically 10 years: 3-4 year investment period, then follow-ons and harvesting through exits.", category: "Fundamentals" },
  { q: "What are VC exit strategies?", a: "IPO, M&A (strategic acquisition), secondary sale, or (worst case) shutdown/write-off.", category: "Fundamentals" },
  // DEAL TERMS (30)
  { q: "What is a term sheet?", a: "Non-binding document outlining investment terms: valuation, amount, liquidation preferences, board seats, anti-dilution.", category: "Deal Terms" },
  { q: "Pre-money vs post-money valuation?", a: "Pre = value before investment. Post = pre + investment. Your ownership = investment / post-money.", category: "Deal Terms" },
  { q: "What is a liquidation preference?", a: "Investor gets money back (1x) before common in a sale. 1x non-participating is standard.", category: "Deal Terms" },
  { q: "Participating vs non-participating preferred?", a: "Non-participating: choose between pref or common share. Participating: get pref back PLUS share in remaining (double-dip).", category: "Deal Terms" },
  { q: "What is anti-dilution protection?", a: "Protects investors if future rounds are at lower valuations. Weighted average (common) or full ratchet (harsh).", category: "Deal Terms" },
  { q: "What is a SAFE?", a: "Simple Agreement for Future Equity — not debt, converts to equity at next priced round with discount/cap. Y Combinator standard.", category: "Deal Terms" },
  { q: "What is a convertible note?", a: "Debt that converts to equity at next priced round, usually with discount and/or valuation cap.", category: "Deal Terms" },
  { q: "Discount vs cap in a note?", a: "Discount: buy shares at X% less than round price. Cap: maximum valuation for conversion. Both protect early investors.", category: "Deal Terms" },
  { q: "What is a pro rata right?", a: "Right to invest in future rounds to maintain ownership %. Valuable for successful companies.", category: "Deal Terms" },
  { q: "What is a board seat?", a: "Lead investor typically gets a board seat to influence governance, strategy, and protect their investment.", category: "Deal Terms" },
  { q: "What is a drag-along right?", a: "Allows majority shareholders to force minority to join a sale. Prevents small holders from blocking exits.", category: "Deal Terms" },
  { q: "What is tag-along right?", a: "Allows minority shareholders to join if majority sells. Protects minority from being left behind.", category: "Deal Terms" },
  { q: "What is information rights?", a: "Investor's right to receive regular financial reports and updates. Standard for significant investors.", category: "Deal Terms" },
  { q: "What is a vesting schedule?", a: "Typically 4-year vesting with 1-year cliff. Founders/employees earn equity over time. Protects against early departure.", category: "Deal Terms" },
  { q: "What is an 83(b) election?", a: "IRS filing letting founders pay taxes on stock at grant (low value) rather than at vesting (potentially high value).", category: "Deal Terms" },
  // SAAS METRICS (25)
  { q: "What is ARR/MRR?", a: "Annual/Monthly Recurring Revenue. Core top-line metric for subscriptions. Growth rate and quality matter.", category: "SaaS Metrics" },
  { q: "What is net dollar retention (NDR)?", a: "Revenue from existing customers this year / last year. >100% means expansion > churn. >120% is excellent.", category: "SaaS Metrics" },
  { q: "What is CAC?", a: "Customer Acquisition Cost. Total sales + marketing spend / new customers acquired. Lower is better.", category: "SaaS Metrics" },
  { q: "What is LTV?", a: "Lifetime Value = avg revenue × gross margin × avg customer lifespan. LTV/CAC > 3x is healthy.", category: "SaaS Metrics" },
  { q: "What is LTV/CAC?", a: "Key unit economics ratio. >3x generally healthy. Shows each customer generates well more than cost to acquire.", category: "SaaS Metrics" },
  { q: "What is CAC payback period?", a: "Months to recover acquisition cost from gross margin. <12 months is good. >18 months is concerning.", category: "SaaS Metrics" },
  { q: "What is gross churn vs net churn?", a: "Gross churn: total revenue lost from churned customers. Net churn: gross churn offset by expansion from remaining customers.", category: "SaaS Metrics" },
  { q: "What is logo churn vs revenue churn?", a: "Logo: % customers lost. Revenue: % revenue lost. Can differ if large customers churn vs small ones.", category: "SaaS Metrics" },
  { q: "What is expansion revenue?", a: "Additional revenue from existing customers through upsells, cross-sells, or usage growth.", category: "SaaS Metrics" },
  { q: "What is Rule of 40?", a: "Revenue growth % + profit margin % should exceed 40% for healthy SaaS companies. Balances growth with efficiency.", category: "SaaS Metrics" },
  { q: "What is gross margin for SaaS?", a: "Typically 70-85%. Includes hosting, support, customer success costs. Higher is better.", category: "SaaS Metrics" },
  { q: "What is ACV?", a: "Annual Contract Value. Average annual revenue per contract. Higher ACV = more enterprise-focused.", category: "SaaS Metrics" },
  { q: "What is magic number?", a: "Net new ARR / prior quarter sales & marketing spend. Measures sales efficiency. >1x is good.", category: "SaaS Metrics" },
  { q: "What is burn rate?", a: "Monthly cash consumed. Revenue - all expenses. Lower burn = longer runway.", category: "SaaS Metrics" },
  { q: "What is runway?", a: "Cash / monthly burn rate = months until cash runs out. 12-18 months is comfortable.", category: "SaaS Metrics" },
  // MARKET & EVALUATION (25)
  { q: "What is TAM/SAM/SOM?", a: "Total Addressable Market / Serviceable Available / Serviceable Obtainable. Narrows from theoretical to realistic.", category: "Evaluation" },
  { q: "Top-down vs bottom-up TAM?", a: "Top-down: industry reports, broad estimates. Bottom-up: potential customers × price. Bottom-up more credible.", category: "Evaluation" },
  { q: "How do you evaluate a founding team?", a: "Domain expertise, complementary skills, execution track record, resilience, coachability, vision clarity.", category: "Evaluation" },
  { q: "What is a moat for a startup?", a: "Network effects, data advantages, switching costs, brand (rare early), regulatory barriers, technical IP.", category: "Evaluation" },
  { q: "How do you evaluate unit economics?", a: "LTV/CAC, gross margins, payback period, contribution margin. Must be positive and scalable.", category: "Evaluation" },
  { q: "What makes a market attractive for VC?", a: "Large and growing, fragmented, technology-driven disruption possible, willing buyers, venture-scale outcomes.", category: "Evaluation" },
  { q: "What is a venture-scale return?", a: "Potential for 10-100x+ return. VC math requires that winners compensate for the many losses.", category: "Evaluation" },
  { q: "How do you assess competitive landscape?", a: "Direct competitors, adjacent players, incumbent response, differentiation, barriers to entry, market share trajectory.", category: "Evaluation" },
  { q: "What are common startup failure reasons?", a: "No market need (biggest), ran out of cash, wrong team, got outcompeted, pricing/cost issues, bad product, poor timing.", category: "Evaluation" },
  { q: "What is a pivot?", a: "Fundamental change in product, market, or business model based on learnings. Sign of adaptability if done well.", category: "Evaluation" },
  // BEHAVIORAL (15)
  { q: "Why venture capital?", a: "Innovation passion, evaluating founders/markets, long horizon, conviction on trends, helping companies scale.", category: "Behavioral" },
  { q: "What sector thesis excites you?", a: "Pick one you genuinely follow. Know the landscape, key startups, trends, risks. Show intellectual curiosity.", category: "Behavioral" },
  { q: "Tell me about a startup you'd invest in.", a: "Team, market, product, traction, unit economics, competitive position, valuation, risks. Show investor thinking.", category: "Behavioral" },
  { q: "How do you source deals?", a: "Network, events, accelerators, referrals from founders/VCs, cold outreach, thesis-driven research.", category: "Behavioral" },
  { q: "What makes a great VC?", a: "Pattern recognition, founder empathy, conviction, network, willingness to be wrong, value-add beyond capital.", category: "Behavioral" },
  { q: "How do you add value as a VC?", a: "Introductions, hiring help, strategic advice, follow-on capital, governance, customer connections.", category: "Behavioral" },
  { q: "Tell me about yourself.", a: "Interest in technology/startups → analytical skills → relevant experience → why VC combines all of these.", category: "Behavioral" },
];

// ── RESTRUCTURING (150+) ──
export const RX_FLASHCARDS: Flashcard[] = [
  // FUNDAMENTALS (25)
  { q: "What is restructuring?", a: "Reorganizing a company's financial structure, operations, or capital when facing distress or needing transformation.", category: "Fundamentals" },
  { q: "What causes financial distress?", a: "Over-leverage, revenue decline, liquidity crunch, covenant breach, operational problems, industry disruption, litigation.", category: "Fundamentals" },
  { q: "What is a covenant breach?", a: "Violating debt agreement restrictions (leverage, coverage). Can trigger default, accelerate debt, force restructuring.", category: "Fundamentals" },
  { q: "In-court vs out-of-court restructuring?", a: "Out-of-court: negotiated with creditors, faster, cheaper. In-court (Ch.11): court-supervised, binding on all, more tools available.", category: "Fundamentals" },
  { q: "What is a forbearance agreement?", a: "Creditor agrees not to exercise default rights for a period while debtor negotiates a restructuring.", category: "Fundamentals" },
  { q: "What is an amend and extend?", a: "Modifying loan terms to push out maturity and potentially adjust covenants. Avoids default without full restructuring.", category: "Fundamentals" },
  { q: "What is a distressed exchange?", a: "Exchanging existing debt for new securities (often at a discount or with equity). Out-of-court restructuring tool.", category: "Fundamentals" },
  { q: "What is a liability management exercise (LME)?", a: "Transactions to address debt maturities, reduce leverage, or improve liquidity outside of formal restructuring.", category: "Fundamentals" },
  { q: "What is a going concern vs liquidation?", a: "Going concern: business continues operating. Liquidation: assets sold, company wound down. Going concern usually yields more value.", category: "Fundamentals" },
  { q: "What are the three sides in restructuring?", a: "Company (debtor), creditors (lenders/bondholders), equity. Each has different interests. Banks advise all three.", category: "Fundamentals" },
  // BANKRUPTCY (35)
  { q: "What is Chapter 11?", a: "US bankruptcy allowing reorganization while operating. Debtor-in-possession. Ends with plan of reorganization.", category: "Bankruptcy" },
  { q: "What is Chapter 7?", a: "Liquidation — company ceases operations, assets sold to repay creditors in priority order.", category: "Bankruptcy" },
  { q: "What is the automatic stay?", a: "Upon filing, all creditor actions (lawsuits, collections) are paused. Gives debtor breathing room.", category: "Bankruptcy" },
  { q: "What is debtor-in-possession (DIP)?", a: "In Ch.11, existing management continues running the company (with court oversight) rather than a trustee.", category: "Bankruptcy" },
  { q: "What is a DIP loan?", a: "New financing during Ch.11 with super-priority status. Allows company to operate while restructuring.", category: "Bankruptcy" },
  { q: "What is the absolute priority rule?", a: "Claims paid in order: secured → administrative → unsecured → subordinated → preferred → common. Each class paid before next.", category: "Bankruptcy" },
  { q: "What is a cramdown?", a: "Court confirms a plan over objection of a dissenting class, if plan is fair and equitable.", category: "Bankruptcy" },
  { q: "What is a 363 sale?", a: "Sale of assets under Section 363. Often through auction. Buyer gets assets free of liens.", category: "Bankruptcy" },
  { q: "What is a pre-pack?", a: "Pre-negotiated reorganization plan agreed with key creditors before filing. Faster emergence.", category: "Bankruptcy" },
  { q: "What is a pre-arranged bankruptcy?", a: "Key terms negotiated pre-filing but plan voted on after filing. Between pre-pack and free-fall.", category: "Bankruptcy" },
  { q: "What is a plan of reorganization?", a: "The blueprint for restructured company: new capital structure, claim treatment, governance, operations.", category: "Bankruptcy" },
  { q: "What is a disclosure statement?", a: "Document providing creditors adequate information to vote on the plan. Must be approved by court.", category: "Bankruptcy" },
  { q: "What is voting on a plan?", a: "Each class of claims votes. Acceptance: 2/3 in amount and 1/2 in number within each class.", category: "Bankruptcy" },
  { q: "What are executory contracts?", a: "Contracts where both parties still have obligations. In Ch.11, debtor can assume (keep) or reject (terminate).", category: "Bankruptcy" },
  { q: "What is avoidance actions?", a: "Trustee/debtor can claw back preferential transfers (within 90 days) or fraudulent transfers.", category: "Bankruptcy" },
  { q: "What is adequate protection?", a: "Secured creditors' right to protection against decline in collateral value during bankruptcy.", category: "Bankruptcy" },
  { q: "What is a UCC?", a: "Unsecured Creditors' Committee. Represents unsecured creditors' interests in Ch.11 proceedings.", category: "Bankruptcy" },
  { q: "What is first-day motions?", a: "Immediate court requests at filing: pay employees, honor customer programs, pay critical vendors, use cash collateral.", category: "Bankruptcy" },
  { q: "What is cash collateral?", a: "Cash or cash equivalents subject to a lien. Debtor needs court permission to use it.", category: "Bankruptcy" },
  { q: "What is emergence?", a: "When the restructured company exits bankruptcy with a new capital structure and plan effective.", category: "Bankruptcy" },
  { q: "What is a rights offering?", a: "Post-emergence equity offering to creditors/new investors. Raises capital as part of reorganization.", category: "Bankruptcy" },
  { q: "What is equitable subordination?", a: "Court can subordinate a creditor's claim if they engaged in inequitable conduct (fraud, breach of fiduciary duty).", category: "Bankruptcy" },
  // VALUATION & ANALYSIS (30)
  { q: "What is the fulcrum security?", a: "The class in the capital structure where value breaks — partially impaired. Senior gets full recovery; junior gets nothing.", category: "Valuation" },
  { q: "How do you find the fulcrum?", a: "Estimate EV, then work down the capital structure: secured → unsecured → sub → equity. Where EV runs out.", category: "Valuation" },
  { q: "What is recovery analysis?", a: "Estimates what each class receives under different scenarios (reorganization vs liquidation). Drives negotiation.", category: "Valuation" },
  { q: "What is a liquidity analysis?", a: "Projects cash flows (often 13-week) to determine when/if the company runs out of cash.", category: "Valuation" },
  { q: "What is EV in distressed context?", a: "Total value available for claimants. Estimated via distressed comps, asset liquidation, or going-concern DCF.", category: "Valuation" },
  { q: "What is a liquidation analysis?", a: "Estimates recovery from selling all assets. Usually produces lower values than going-concern. Used as a floor.", category: "Valuation" },
  { q: "How do you value a distressed company?", a: "Going-concern DCF (if viable), distressed comps, asset-based valuation, sum-of-parts, liquidation analysis.", category: "Valuation" },
  { q: "What is a recovery rate?", a: "Cents on the dollar a creditor receives. Secured typically 60-80%+. Unsecured varies widely.", category: "Valuation" },
  { q: "What is loan-to-value in distressed?", a: "Debt / estimated going-concern value. Shows if debt is over- or under-secured.", category: "Valuation" },
  { q: "What is a credit bid?", a: "Secured creditor bids its claim value in a 363 sale, effectively converting debt to ownership.", category: "Valuation" },
  { q: "What is a section 1111(b) election?", a: "Allows undersecured creditors to treat their full claim as secured. Strategic decision in bankruptcy.", category: "Valuation" },
  { q: "What is a make-whole premium?", a: "Prepayment penalty ensuring the lender receives the full economic benefit of the loan. Often disputed in bankruptcy.", category: "Valuation" },
  { q: "What drives restructuring negotiation?", a: "Relative leverage: who controls the fulcrum, liquidity position, value estimates, strategic alternatives, litigation threats.", category: "Valuation" },
  { q: "What is new money?", a: "Fresh capital invested during or after restructuring. Often comes with favorable terms (DIP, rights offering).", category: "Valuation" },
  { q: "What is a plan currency?", a: "What creditors receive under the plan: new debt, new equity, cash, warrants, or combination.", category: "Valuation" },
  // CAPITAL STRUCTURE (20)
  { q: "What is the priority of claims?", a: "Super-priority (DIP) → secured → administrative → priority unsecured → general unsecured → subordinated → equity.", category: "Capital Structure" },
  { q: "First lien vs second lien?", a: "First lien: priority on collateral. Second lien: subordinate — higher risk, higher yield, lower recovery.", category: "Capital Structure" },
  { q: "What is an intercreditor agreement?", a: "Agreement between first and second lien lenders defining rights, remedies, and priorities between them.", category: "Capital Structure" },
  { q: "What is subordination?", a: "Contractual or structural arrangement where one class's claims rank below another's.", category: "Capital Structure" },
  { q: "Structural vs contractual subordination?", a: "Structural: claims at subsidiary level (parent creditors get what's left). Contractual: explicit agreement to rank below.", category: "Capital Structure" },
  { q: "What is a revolver in distress?", a: "Usually drawn fully before filing. Super-senior in capital structure. Repaid early in restructuring.", category: "Capital Structure" },
  { q: "What is a term loan in distressed?", a: "Senior secured debt. Syndicated among institutional investors. Recovery depends on collateral coverage.", category: "Capital Structure" },
  { q: "What are senior unsecured notes?", a: "Bonds without collateral. Below secured debt in priority. Recovery often 20-50% in distress.", category: "Capital Structure" },
  { q: "What is trade debt in bankruptcy?", a: "Amounts owed to vendors/suppliers. Can be critical (essential for operations) or general unsecured.", category: "Capital Structure" },
  { q: "What is an ad hoc group?", a: "Informal creditor group formed to negotiate collectively. Often holds significant claims in a specific class.", category: "Capital Structure" },
  // BEHAVIORAL (15)
  { q: "Why restructuring?", a: "Most intellectually demanding area of finance. Complex capital structures, high stakes, legal/financial/operational intersection.", category: "Behavioral" },
  { q: "Debtor-side vs creditor-side advisory?", a: "Debtor: help company reorganize. Creditor: protect creditor recovery. Both require deep analysis of claims and value.", category: "Behavioral" },
  { q: "What restructuring deal have you followed?", a: "Know the company, capital structure, what went wrong, key negotiation dynamics, outcome.", category: "Behavioral" },
  { q: "What makes someone good at RX?", a: "Comfort with ambiguity, attention to detail in complex cap structures, negotiation, pressure tolerance, cross-functional thinking.", category: "Behavioral" },
  { q: "How is RX different from M&A?", a: "RX: adversarial multi-party negotiation, legal complexity, time pressure, declining business. M&A: cooperative, growth-oriented.", category: "Behavioral" },
  { q: "Tell me about yourself.", a: "Analytical rigor → interest in complex problems → why finance/restructuring → relevant experience.", category: "Behavioral" },
  { q: "How do you handle pressure?", a: "RX is high-stakes with tight deadlines. Show composure, prioritization, attention to detail under pressure.", category: "Behavioral" },
];
